class DFA:
 def __init__(self, states, alphabet, transition, start_state, final_states):
 self.states = states
 self.alphabet = alphabet
 self.transition = transition
 self.start_state = start_state
 self.final_states = final_states

 def accepts(self, input_string):
 current_state = self.start_state
 for symbol in input_string:
 if symbol not in self.alphabet:
 return False
 current_state = self.transition[(current_state, symbol)]
 return current_state in self.final_states

# DFA for language: strings over {a,b} ending with 'ab'
states = {'q0', 'q1', 'q2'}
alphabet = {'a', 'b'}
transition = {
 ('q0', 'a'): 'q1', ('q0', 'b'): 'q0',
 ('q1', 'a'): 'q1', ('q1', 'b'): 'q2',
 ('q2', 'a'): 'q1', ('q2', 'b'): 'q0'
}
start_state = 'q0'
final_states = {'q2'}

dfa = DFA(states, alphabet, transition, start_state, final_states)
print(dfa.accepts('ab')) # True
print(dfa.accepts('aab')) # True
print(dfa.accepts('bab')) # False

FUNCTION SubsetConstruction(NFA):
 // NFA = (Q, Σ, δ, q0, F)
 DFA_states = empty set
 DFA_transitions = empty map
 DFA_final_states = empty set

 // Step 1: Find initial DFA state
 initial = EpsilonClosure({q0}) // ε-closure of start state
 DFA_states = {initial}
 unmarked_states = {initial}

 WHILE unmarked_states is not empty:
 T = remove one state from unmarked_states

 FOR each input symbol a in Σ:
 U = empty set
 FOR each state s in T:
 U = U ∪ δ(s, a) // All reachable states
 U = EpsilonClosure(U) // Include ε-closures

 IF U is not in DFA_states:
 DFA_states = DFA_states ∪ {U}
 unmarked_states = unmarked_states ∪ {U}

 DFA_transitions[(T, a)] = U

 // Step 2: Find final states
 FOR each state T in DFA_states:
 IF T ∩ F ≠ ∅:
 DFA_final_states = DFA_final_states ∪ {T}

 RETURN DFA(DFA_states, Σ, DFA_transitions, initial, DFA_final_states)
